mapper.select:
SELECT EXISTS (
    SELECT 1 FROM franchise WHERE manager_id = #{managerId}
)

SELECT EXISTS (
    SELECT 1 FROM franchise WHERE department_id = #{departmentId}
)

SELECT EXISTS (
    SELECT 1 FROM franchise WHERE owner_id = #{userId}
)

SELECT a.year, a.month, a.`order_quantity` AS `orderQuantity`, a.`product_id` AS `productId`, b.`code` AS `productCode`, b.`name` AS `productName`, b.`purchase_price` AS `productPurchasePrice`, b.`sale_price` AS `productSalePrice`, b.`purchase_unit` AS `productPurchaseUnit`, b.`unit` AS `productUnit`, b.`spec` AS `productSpec`, c.`name` AS `productAttributeName`, d.`name` AS `productGroupName`, e.`name` AS `productTypeName` FROM `franchise_product_order_stat` a JOIN `franchise` f ON a.franchise_id = f.id LEFT JOIN `product` b ON a.product_id = b.id LEFT JOIN `product_attribute` c ON b.product_attribute_id = c.id LEFT JOIN `product_group` d ON b.product_group_id = d.id LEFT JOIN `product_type` e ON b.product_type_id = e.id WHERE f.manager_id = #{managerId}
AND a.`year` = #{year}
AND a.`month` = #{month}

SELECT a.year, a.month, a.`order_quantity` AS `orderQuantity`, a.`product_id` AS `productId`, b.`code` AS `productCode`, b.`name` AS `productName`, b.`purchase_price` AS `productPurchasePrice`, b.`sale_price` AS `productSalePrice`, b.`purchase_unit` AS `productPurchaseUnit`, b.`unit` AS `productUnit`, b.`spec` AS `productSpec`, c.`name` AS `productAttributeName`, d.`name` AS `productGroupName`, e.`name` AS `productTypeName` FROM `franchise_product_order_stat` a JOIN `franchise` f ON a.franchise_id = f.id LEFT JOIN `product` b ON a.product_id = b.id LEFT JOIN `product_attribute` c ON b.product_attribute_id = c.id LEFT JOIN `product_group` d ON b.product_group_id = d.id LEFT JOIN `product_type` e ON b.product_type_id = e.id WHERE f.owner_id = #{userId}
AND a.`year` = #{year}
AND a.`month` = #{month}

SELECT a.year, a.month, a.order_quantity AS orderQuantity, a.product_id AS productId, b.code AS productCode, b.name AS productName, b.purchase_price AS productPurchasePrice, b.sale_price AS productSalePrice, b.purchase_unit AS productPurchaseUnit, b.unit AS productUnit, b.spec AS productSpec, c.name AS productAttributeName, d.name AS productGroupName, e.name AS productTypeName FROM franchise_product_order_stat a JOIN franchise f ON a.franchise_id = f.id LEFT JOIN product b ON a.product_id = b.id LEFT JOIN product_attribute c ON b.product_attribute_id = c.id LEFT JOIN product_group d ON b.product_group_id = d.id LEFT JOIN product_type e ON b.product_type_id = e.id WHERE f.department_id = #{departmentId}
AND a.year = #{year}
AND a.month = #{month}
